import * as React from "react";

import { cn } from "../utils/cn";

/* -------------------------------------------------------------------------- */
/*  Types                                                                     */
/* -------------------------------------------------------------------------- */

type PaginationProps = {
  /** Current active page (1-based). */
  currentPage: number;
  /** Total number of pages. */
  totalPages: number;
  /** Called with the new page number when the user navigates. */
  onPageChange: (page: number) => void;
  /**
   * Number of sibling pages shown on each side of the current page.
   * Defaults to 1 (e.g. 1 ... 4 [5] 6 ... 10).
   */
  siblingCount?: number;
  className?: string;
};

/* -------------------------------------------------------------------------- */
/*  Helpers                                                                   */
/* -------------------------------------------------------------------------- */

const ELLIPSIS = "ellipsis" as const;
type PageItem = number | typeof ELLIPSIS;

/**
 * Builds a compact page range like Vuetify's v-pagination:
 *   [1] ... [4] [5] [6] ... [10]
 */
function getPageRange(
  currentPage: number,
  totalPages: number,
  siblingCount: number,
): PageItem[] {
  // Total page numbers we want to show (excluding ellipses)
  const totalPageNumbers = siblingCount * 2 + 5;
  // first + last + current + 2 siblings + 2 ellipses

  // If total pages fits within our budget, show all pages
  if (totalPages <= totalPageNumbers) {
    return Array.from({ length: totalPages }, (_, i) => i + 1);
  }

  const leftSiblingIndex = Math.max(currentPage - siblingCount, 1);
  const rightSiblingIndex = Math.min(currentPage + siblingCount, totalPages);

  const showLeftEllipsis = leftSiblingIndex > 2;
  const showRightEllipsis = rightSiblingIndex < totalPages - 1;

  if (!showLeftEllipsis && showRightEllipsis) {
    // Show more pages on the left
    const leftItemCount = 3 + 2 * siblingCount;
    const leftRange = Array.from({ length: leftItemCount }, (_, i) => i + 1);
    return [...leftRange, ELLIPSIS, totalPages];
  }

  if (showLeftEllipsis && !showRightEllipsis) {
    // Show more pages on the right
    const rightItemCount = 3 + 2 * siblingCount;
    const rightRange = Array.from(
      { length: rightItemCount },
      (_, i) => totalPages - rightItemCount + i + 1,
    );
    return [1, ELLIPSIS, ...rightRange];
  }

  // Both ellipses
  const middleRange = Array.from(
    { length: rightSiblingIndex - leftSiblingIndex + 1 },
    (_, i) => leftSiblingIndex + i,
  );
  return [1, ELLIPSIS, ...middleRange, ELLIPSIS, totalPages];
}

/* -------------------------------------------------------------------------- */
/*  Component                                                                 */
/* -------------------------------------------------------------------------- */

/**
 * Pagination controls matching Vuetify v-pagination visual style.
 *
 * Renders Previous/Next buttons flanking numbered page buttons
 * with ellipsis for large page counts.
 */
function Pagination({
  currentPage,
  totalPages,
  onPageChange,
  siblingCount = 1,
  className,
}: PaginationProps) {
  if (totalPages <= 0) return null;

  const pages = getPageRange(currentPage, totalPages, siblingCount);

  const handlePrevious = () => {
    if (currentPage > 1) onPageChange(currentPage - 1);
  };

  const handleNext = () => {
    if (currentPage < totalPages) onPageChange(currentPage + 1);
  };

  return (
    <nav
      data-slot="pagination"
      aria-label="Pagination"
      className={cn("flex items-center gap-1", className)}
    >
      {/* Previous */}
      <button
        data-slot="pagination-previous"
        type="button"
        aria-label="Go to previous page"
        disabled={currentPage <= 1}
        onClick={handlePrevious}
        className={cn(
          "inline-flex size-9 items-center justify-center rounded-md text-sm transition-colors",
          "hover:bg-surface focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary",
          "disabled:pointer-events-none disabled:opacity-40",
        )}
      >
        <ChevronLeftSvg className="size-4" />
      </button>

      {/* Page numbers */}
      {pages.map((page, index) => {
        if (page === ELLIPSIS) {
          return (
            <span
              key={`ellipsis-${index}`}
              data-slot="pagination-ellipsis"
              className="inline-flex size-9 items-center justify-center text-sm text-muted-foreground select-none"
              aria-hidden="true"
            >
              ...
            </span>
          );
        }

        const isActive = page === currentPage;
        return (
          <button
            key={page}
            type="button"
            data-slot="pagination-item"
            aria-label={`Go to page ${page}`}
            aria-current={isActive ? "page" : undefined}
            onClick={() => onPageChange(page)}
            className={cn(
              "inline-flex size-9 items-center justify-center rounded-md text-sm font-medium transition-colors",
              "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary",
              isActive
                ? "bg-primary text-primary-foreground"
                : "hover:bg-surface text-foreground",
            )}
          >
            {page}
          </button>
        );
      })}

      {/* Next */}
      <button
        data-slot="pagination-next"
        type="button"
        aria-label="Go to next page"
        disabled={currentPage >= totalPages}
        onClick={handleNext}
        className={cn(
          "inline-flex size-9 items-center justify-center rounded-md text-sm transition-colors",
          "hover:bg-surface focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary",
          "disabled:pointer-events-none disabled:opacity-40",
        )}
      >
        <ChevronRightSvg className="size-4" />
      </button>
    </nav>
  );
}

/* -------------------------------------------------------------------------- */
/*  Inline SVGs                                                               */
/* -------------------------------------------------------------------------- */

function ChevronLeftSvg(props: React.ComponentProps<"svg">) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      {...props}
    >
      <path d="m15 18-6-6 6-6" />
    </svg>
  );
}

function ChevronRightSvg(props: React.ComponentProps<"svg">) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      {...props}
    >
      <path d="m9 18 6-6-6-6" />
    </svg>
  );
}

/* -------------------------------------------------------------------------- */
/*  Exports                                                                   */
/* -------------------------------------------------------------------------- */

export { Pagination, getPageRange };
export type { PaginationProps };
